import{_ as p}from"./plugin-vue_export-helper.21dcd24c.js";import{o as r,c as e,a as o}from"./app.33f516a9.js";const t={},c=o("<p>\u73B0\u5728\u662F\u665A\u4E0A\u63A5\u8FD12\u70B9\uFF0C\u521A\u624D\u4E0A\u53BB\u6572\u697C\u4E0A\u7684\u95E8\u3002</p><p>\u697C\u4E0A\u662F\u5927\u6982\u4E24\u5E74\u524D\u642C\u8FC7\u6765\u7684\u62C6\u8FC1\u6237\uFF0C\u642C\u6765\u7684\u65F6\u5019\u5C31\u5404\u79CD\u4E52\u4E52\u4E53\u4E53\uFF0C\u4E0D\u5206\u663C\u591C\u3002\u4F46\u662F\u8003\u8651\u4EBA\u5BB6\u521A\u642C\u6765\u6709\u5404\u79CD\u4E1C\u897F\u8981\u6574\u7406\uFF0C\u6211\u60F3\u8FD9\u4E5F\u662F\u60C5\u7406\u4E4B\u4E2D\uFF0C\u8C01\u53EF\u80FD\u90FD\u6709\u8FD9\u79CD\u65F6\u5019\u3002</p><p>\u4F46\u662F\u6211\u60F3\u9519\u4E86\uFF0C\u540E\u9762\u6211\u5C31\u5F00\u59CB\u8FDB\u5165\u4E86\u4E00\u79CD\u5FAA\u73AF\u7684\u5669\u68A6\u72B6\u6001\u3002</p><p>\u5728\u697C\u4E0A\u8FD9\u5BB6\u642C\u6765\u4E4B\u524D\uFF0C\u4E0A\u4E00\u4EFB\u79DF\u6237\uFF0C\u662F\u90A3\u79CD\u5F88\u597D\u8BF4\u8BDD\uFF0C\u7D20\u8D28\u53C8\u597D\u7684\u90BB\u5C45\u3002\u5E73\u65F6\u867D\u7136\u6CA1\u592A\u591A\u4EA4\u96C6\uFF0C\u4F46\u662F\u4ED6\u4EEC\u4E00\u5BB6\u4E3A\u4EBA\u548C\u853C\uFF0C\u4E5F\u5F88\u6CE8\u91CD\u5F71\u54CD\uFF0C\u4E0D\u4F1A\u4E0D\u5206\u663C\u591C\u5236\u9020\u566A\u97F3\u5F71\u54CD\u5176\u4ED6\u4EBA\u3002\u4E00\u6B21\u56E0\u4E3A\u4ED6\u4EEC\u6C34\u7BA1\u63A5\u53E3\u8001\u5316\u6F0F\u6C34\u5BFC\u81F4\u6211\u4EEC\u540A\u9876\u53D1\u9709\uFF0C\u4EBA\u5BB6\u90FD\u597D\u58F0\u597D\u6C14\u914D\u5408\u4F60\u5904\u7406\u3002\u8FD8\u6709\u4E00\u6B21\u56E0\u4E3A\u4ED6\u4EEC\u7684\u7A7A\u8C03\u4E3B\u673A\u6392\u6C34\uFF0C\u4E5F\u662F\u8BA9\u98D8\u7A97\u9876\u4E0A\u53D7\u6F6E\u53D1\u9709\uFF0C\u8FD9\u5BB6\u7537\u4E3B\u4EBA\u8FD8\u548C\u6211\u4E00\u8D77\u722C\u5230\u5916\u9762\u53BB\u5F04\u5916\u673A\u6392\u6C34\u7BA1\u3002</p><p>\u540E\u6765\u4ED6\u4EEC\u642C\u8D70\u540E\uFF0C\u542C\u8BF4\u60F3\u4E70\u4E0B\u5F53\u65F6\u7684\u8FD9\u4E2A\u79DF\u7684\u623F\u5B50\uFF0C\u4F46\u662F\u623F\u4E1C\u4E0D\u60F3\u5356\u3002\u697C\u4E0A\u7684\u623F\u4E1C\u4ED6\u4EEC\u662F\u7ECF\u5E38\u5728\u5916\u5730\u7684\uFF0C\u5E73\u65F6\u53EF\u80FD\u4E5F\u5F88\u5C11\u56DE\u6765\uFF0C\u53EF\u80FD\u623F\u5B50\u60F3\u7559\u7740\u56DE\u8001\u5BB6\u517B\u8001\u4F4F\u5427\u3002</p><p>\u81EA\u4ECE\u73B0\u5728\u7684\u8FD9\u5BB6\u79DF\u6237\u6765\u4E86\u4EE5\u540E\uFF0C\u6211\u4E0A\u53BB\u6572\u8FC7\u5F88\u591A\u6B21\u95E8\u3002\u4E0D\u662F\u6211\u6545\u610F\u53BB\u627E\u4EBA\u5BB6\u4E8B\u60C5\uFF0C\u800C\u662F\u771F\u7684\u6CA1\u6709\u529E\u6CD5\uFF0C\u4E0D\u7136\u8C01\u613F\u610F\u4E00\u5929\u5230\u665A\u53BB\u8DDF\u4F60\u6572\u95E8\u4EA4\u6D89\u3002</p><p>\u8BF4\u8BF4\u5177\u4F53\u7684\u5427\u3002</p><hr><p>\u7B2C\u4E00\u6B21\u662F\u5241\u8089\uFF0C\u5F53\u5929\u4ECE\u65E9\u6668\u4E00\u76F4\u5241\u5230\u4E0B\u5348\u508D\u665A\u3002\u549A\u549A\u549A\u7684\u58F0\u97F3\u4E0B\u9762\u5435\u4E86\u4E00\u6574\u5929\uFF0C\u5241\u8089\u6211\u89C9\u5F97\u5F88\u6B63\u5E38\uFF0C\u4F46\u662F\u5241\u4E00\u5929\u4E0D\u6B63\u5E38\uFF0C\u56E0\u4E3A\u771F\u7684\u53D7\u4E0D\u4E86\u3002\u4E0A\u53BB\u6572\u95E8\uFF0C\u4ED6\u4EEC\u8BF4\u5241\u8089\u4E5F\u4E0D\u884C\uFF1F\u6211\u8BF4\u4E0D\u662F\u5241\u8089\u4E0D\u884C\uFF0C\u4F46\u662F\u8FD9\u4E2A\u5241\u8089\u5241\u4E00\u5929\uFF0C\u6CA1\u8FD9\u4E2A\u5241\u6CD5\u554A\u3002</p><p>\u697C\u4E0A\u5973\u4EBA\u8BF4\u662F\u5B69\u5B50\u60F3\u5403\u997A\u5B50\uFF0C\u81EA\u5DF1\u5305\u70B9\u997A\u5B50\uFF0C\u6211\u7238\u5F53\u65F6\u8BF4\u5982\u679C\u60F3\u8981\u5F04\u997A\u5B50\u9985\uFF0C\u53EF\u4EE5\u5F04\u90A3\u79CD\u7EDE\u8089\u673A\u6BD4\u8F83\u65B9\u4FBF\uFF0C\u53C8\u4E0D\u7528\u4E00\u76F4\u5241\uFF0C\u5F04\u8D77\u6765\u4E5F\u5F88\u5FEB\u3002\u5973\u4EBA\u5F88\u5F3A\u52BF\u8BF4\uFF0C\u6211\u5728\u5BB6\u5F04\u4EC0\u4E48\u8FD8\u8981\u4F60\u7BA1\uFF0C\u5F53\u65F6\u6211\u5C31\u6709\u70B9\u751F\u6C14\u4E86\uFF0C\u6211\u8BF4\u6211\u4E0D\u7BA1\u4F60\u5F04\u4EC0\u4E48\uFF0C\u4F60\u4E0D\u8981\u5F71\u54CD\u522B\u4EBA\u884C\u4E0D\u884C\uFF0C\u8BA9\u4F60\u4F4F\u697C\u4E0B\u4F60\u6765\u611F\u53D7\u4E0B...</p><p>\u8FD9\u4EF6\u4E8B\u540E\u9762\u4ED6\u4EEC\u5241\u8089\u9891\u7387\u4E5F\u6CA1\u6709\u592A\u9891\u7E41\uFF0C\u6240\u4EE5\u6211\u4E5F\u6CA1\u8BF4\u4EC0\u4E48\uFF0C\u6BD5\u7ADF\u751F\u6D3B\u566A\u97F3\u5F88\u6B63\u5E38\uFF0C\u53EA\u662F\u4E0D\u8981\u4E00\u5929\u5230\u665A\u90FD\u662F\u8FD9\u79CD\u5C31\u53EF\u4EE5\u3002</p><hr><p>\u7B2C\u4E8C\u6B21\uFF0C\u5929\u5929\u667E\u88AB\u5B50\uFF0C\u8FD9\u4E2A\u503C\u5F97\u80AF\u5B9A\uFF0C\u6BD5\u7ADF\u7231\u536B\u751F\u662F\u597D\u4E8B\uFF0C\u56E0\u4E3A\u6211\u90FD\u5F88\u5C11\u667E\u88AB\u5B50\u3002\u4F46\u662F\u4F60\u4ED6\u5988\u667E\u88AB\u5B50\u80FD\u4E0D\u80FD\u53E0\u8D77\u6765\uFF0C\u5C31\u76F4\u63A5\u7528\u5939\u5B50\u5939\u4F4F\u4E00\u8FB9\uFF0C\u76F4\u63A5\u5F80\u4E0B\u62D6\u7740\u3002\u597D\u5BB6\u4F19\uFF0C\u8FD9\u5BB6\u91CC\u77AC\u95F4\u5C31\u6697\u4E86\uFF0C\u6211\u4F38\u624B\u5C31\u80FD\u591F\u7740\u4ED6\u4EEC\u88AB\u5B50\u3002</p><p>\u6CA1\u529E\u6CD5\uFF0C\u6211\u53C8\u4E0A\u697C\u4E86\u3002\u90A3\u4E2A\u5973\u4EBA\u8FD8\u662F\u90A3\u53E5\u8BDD\uFF0C\u6211\u5728\u5BB6\u667E\u88AB\u5B50\u8FD8\u80FD\u5F71\u54CD\u5230\u4F60\uFF1F\u88AB\u5B50\u4E5F\u4E0D\u80FD\u667E\u4E86\uFF1F\u5F53\u7136\u6211\u89C9\u5F97\u6211\u81EA\u5DF1\u4E5F\u4E0D\u662F\u597D\u6B3A\u8D1F\u7684\uFF0C\u6211\u76F4\u63A5\u5C31\u8BF4\u4F60\u6700\u597D\u662F\u5BF9\u6298\u667E\uFF0C\u518D\u5F80\u4E0B\u62D6\u4E0B\u6765\u4F60\u53EF\u80FD\u89C1\u4E0D\u5230\u4F60\u7684\u88AB\u5B50\u3002\u540E\u6765\u51E0\u6B21\u90FD\u5F80\u4E0A\u62C9\u4E86\u4E00\u70B9\u70B9\uFF0C\u4F46\u662F\u8FD8\u662F\u5F80\u4E0B\u62D6\u7740\uFF0C\u53EA\u662F\u6CA1\u62D6\u592A\u957F\uFF0C\u6211\u60F3\u60F3\u5C31\u7B97\u4E86\u3002</p><p>\u6700\u540E\u4E00\u6B21\u662F\u5927\u6982\u4E00\u4E2A\u6708\u524D\uFF0C\u53C8\u50CF\u7B2C\u4E00\u6B21\u62D6\u4E0B\u6765\u4E86\uFF0C\u6211\u53EA\u80FD\u5982\u5979\u6240\u613F\uFF0C\u8BA9\u5979\u53BB\u697C\u4E0B\u6361\u88AB\u5B50\u3002\u6361\u5B8C\u88AB\u5B50\u5C45\u7136\u8FD8\u8BF4\uFF0C\u6CA1\u529E\u6CD5\uFF0C\u88AB\u5B50\u53EA\u80FD\u5BF9\u6298\u667E\uFF0C\u4E0D\u7136\u697C\u4E0B\u53C8\u641E\u6211\u7684\u88AB\u5B50\u3002\u6211\u4ED6\u5988\u662F\u559C\u6B22\u4F60\u88AB\u5B50\u5417\uFF0C\u4F60\u5982\u679C\u597D\u597D\u7684\u6211\u81F3\u4E8E\u5929\u5929\u8DDF\u4F60\u8F83\u52B2\u5417\uFF1F</p><hr><p>\u7B2C\u4E09\u6B21\uFF0C\u697C\u4E0A\u667E\u8863\u670D\u4ECE\u6765\u90FD\u4E0D\u8131\u6C34\uFF0C\u76F4\u63A5\u5F80\u5916\u9762\u62CE\u51FA\u6765\u5C31\u6302\u4E0A\u3002\u8FD9\u4EF6\u4E8B\u6211\u7684\u697C\u4E0B\u5DF2\u7ECF\u5FCD\u65E0\u53EF\u5FCD\uFF0C\u53BB\u5E74\u8FC7\u5E74\u671F\u95F4\u76F4\u63A5\u5C31\u7AD9\u697C\u4E0B\u5F00\u9A82\u4E86\u3002</p><p>\u5F53\u8FD9\u4EF6\u4E8B\u5F71\u54CD\u5230\u6211\u7684\u65F6\u5019\uFF0C\u56E0\u4E3A\u662F\u5F00\u7740\u7A97\u6237\u7684\uFF0C\u5B83\u4EEC\u6EF4\u6C34\u76F4\u63A5\u5C31\u6EF4\u5230\u5BB6\u91CC\u6765\u4E86\u3002\u9042\u7B2C\u4E8C\u6B21\u4E0A\u697C\u4EA4\u6D89\uFF0C\u5F00\u95E8\u7684\u662F\u7537\u4EBA\uFF0C\u6211\u8BF4\u667E\u8863\u670D\u4E0D\u80FD\u8131\u6C34\u518D\u667E\u5417\uFF1F\u4F60\u8FD9\u6837\u697C\u4E0B\u4EBA\u662F\u4E0D\u662F\u4E0D\u7528\u667E\u8863\u670D\u4E86\u3002\u800C\u4E14\u6211\u5F00\u7740\u7A97\u6237\uFF0C\u4F60\u8FD9\u4E2A\u6C34\u76F4\u63A5\u5C31\u6EF4\u5230\u5BB6\u91CC\u6765\u4E86\uFF0C\u90FD\u6CA1\u6CD5\u5F00\u7A97\u3002</p><p>\u7537\u4EBA\u8BF4\u8FD8\u6709\u8FD9\u4E8B\uFF0C\u6211\u53BB\u4F60\u5BB6\u770B\u770B\u4F60\u662F\u4E0D\u662F\u9A97\u6211\u3002\u6211\u987F\u65F6\u706B\u6C14\u5C31\u4E0A\u6765\u4E86\uFF0C\u76F4\u63A5\u5C31\u8BF4\u4E86\uFF0C\u6211\u8BF4\u4F60\u518D\u8FD9\u6837\u667E\u8863\u670D\u7684\u8BDD\u3002\u4F60\u53EF\u80FD\u4EE5\u540E\u522B\u60F3\u7528\u6C34\u7528\u7535\u4E86\uFF0C\u6211\u53CD\u6B63\u6709\u65F6\u95F4\u966A\u4F60\u95F9\u3002\u7537\u4EBA\u7238\u5988\u542C\u58F0\u97F3\u51FA\u6765\u4E86\uFF0C\u4ED6\u7238\u6001\u5EA6\u5F88\u597D\uFF0C\u5C31\u8BF4\u8BA9\u6211\u4F53\u8C05\u4E00\u4E0B\uFF0C\u73B0\u5728\u5C31\u628A\u8863\u670D\u62FF\u8FDB\u6765\u8131\u6C34\u3002</p><p>\u6211\u4E5F\u8868\u8FBE\u4E86\u6211\u7684\u770B\u6CD5\uFF0C\u6211\u8BF4\u4E0D\u662F\u8BF4\u6211\u8981\u653E\u72E0\u8BDD\uFF0C\u6211\u662F\u771F\u7684\u6CA1\u529E\u6CD5\u3002\u90FD\u662F\u697C\u4E0A\u697C\u4E0B\uFF0C\u90BB\u91CC\u4E4B\u95F4\uFF0C\u6211\u4E0D\u662F\u56E0\u4E3A\u4F60\u4EEC\u662F\u79DF\u6237\u800C\u5E26\u6709\u504F\u89C1\uFF0C\u5982\u679C\u5927\u5BB6\u90FD\u4E0D\u8003\u8651\u5176\u4ED6\u4EBA\uFF0C\u90A3\u8FD8\u600E\u4E48\u76F8\u5904\u4E0B\u53BB\u3002\u521A\u624D\u6211\u8BF4\u7684\u4E5F\u662F\u6C14\u8BDD\uFF0C\u8BA9\u4ED6\u4EEC\u4E0D\u8981\u653E\u5FC3\u4E0A... \u6211\u548C\u4ED6\u7238\u63E1\u4E86\u4E2A\u624B\uFF0C\u7136\u540E\u6211\u5C31\u4E0B\u6765\u4E86\u3002</p><p>\u540E\u9762\u8FD8\u6709\u7537\u4EBA\u53C8\u8FD9\u6837\u505A\u4E86\u4E00\u6B21\uFF0C\u8FD9\u6B21\u6211\u6CA1\u4E0A\u53BB\uFF0C\u56E0\u4E3A\u5F53\u65F6\u6CA1\u5F00\u7A97\u6237\uFF0C\u60F3\u60F3\u7B97\u4E86\uFF0C\u65E0\u8BED\u3002</p><hr><p>\u7B2C\u56DB\u6B21\u5E94\u8BE5\u5C31\u662F\u521A\u624D\u4E86\uFF0C\u90A3\u4E2A\u770B\u7535\u89C6\u7684\u58F0\u97F3\uFF0C\u50CF\u662F\u6545\u610F\u8C03\u5F88\u5927\u58F0\u3002\u4E4B\u524D\u4E00\u76F4\u662F\u8FD9\u6837\uFF0C\u5230\u4E86\u665A\u4E0A12\u30011\u70B9\u90FD\u662F\u5F88\u5927\u58F0\uFF0C\u51E0\u6B21\u60F3\u4E0A\u53BB\u8BF4\u4E00\u4E0B\u592A\u665A\u4E86\u770B\u7535\u89C6\u80FD\u4E0D\u80FD\u5C0F\u70B9\u58F0\uFF0C\u4F46\u662F\u60F3\u60F3\u53C8\u7B97\u4E86\u3002</p><p>\u4ECA\u5929\u662F\u771F\u7684\u53D7\u4E0D\u4E86\uFF0C\u8FD8\u5728\u5DE5\u4F5C\u7684\u65F6\u5019\uFF0C\u7A81\u7136\u88AB\u4E00\u80A1\u58F0\u97F3\u5435\u9192\uFF0C\u8001\u5A46\u5728\u623F\u95F4\u7761\u7740\u4E5F\u88AB\u5435\u9192\u4E86\u3002\u8FD9\u6B21\u6BD4\u4EE5\u5F80\u4EFB\u4F55\u4E00\u6B21\u90FD\u8981\u5927\u58F0\uFF0C\u800C\u4E14\u662F\u51CC\u66681\u70B9\u534A\uFF0C\u662F\u7684\u6CA1\u529E\u6CD5\u6211\u53C8\u5F97\u4E0A\u53BB\u3002</p><p>\u7830\u7830\u7830\u51E0\u58F0\u6572\u95E8\u540E\uFF0C\u5F00\u95E8\u7684\u662F\u7537\u4EBA\uFF0C\u4ED6\u4E5F\u77E5\u9053\u6211\u6765\u7684\u76EE\u7684\u3002\u76F4\u63A5\u5F00\u95E8\u5C31\u662F\u4E00\u53E5\uFF0C\u4E0D\u5C31\u662F\u770B\u7535\u89C6\u58F0\u97F3\u5927\u5417\uFF0C\u6211\u5173\u5C0F\u70B9\u5C31\u662F\u4E86\uFF0C\u8001\u4EBA\u5BB6\u8033\u6735\u4E0D\u597D\u3002</p><p>\u4F46\u662F\u636E\u6211\u6240\u77E5\uFF0C\u90A3\u4E2A\u4E3B\u5367\u623F\u95F4\u662F\u4ED6\u4EEC\u81EA\u5DF1\u5728\u4F4F\uFF0C\u8001\u4E24\u53E3\u662F\u4F4F\u5728\u6B21\u5367\u7684\uFF0C\u62FF\u81EA\u5DF1\u7239\u5988\u6765\u505A\u6321\u7BAD\u724C\uFF0C\u662F\u771F\u7684\u53EF\u4EE5666\u554A\u3002</p><p>\u65E2\u7136\u8FD8\u6CA1\u7B49\u6211\u8BF4\u8BDD\uFF0C\u5C31\u77E5\u9053\u662F\u81EA\u5DF1\u7535\u89C6\u58F0\u97F3\u592A\u5927\uFF0C\u4E3A\u4EC0\u4E48\u504F\u504F\u8981\u7B49\u6211\u53BB\u6572\u95E8\u624D\u77E5\u9053\u662F\u4EC0\u4E48\u539F\u56E0\uFF0C\u6240\u4EE5\u6211\u6709\u7406\u7531\u8BA4\u4E3A\uFF0C\u697C\u4E0A\u8FD9\u4E2A\u50BB\u903C\u662F\u6545\u610F\u7684\uFF01</p><p>\u90A3\u4E48\u6211\u4E5F\u4E0D\u80FD\u7ED9\u4F60\u597D\u8138\u8272\u4E86\uFF0C\u76F4\u63A5\u5C31\u5F00\u9A82\u4E86\uFF0C\u76F4\u63A5\u653E\u4E0B\u8BDD\uFF0C\u4F60\u8981\u4E48\u5173\u5C0F\u70B9\u58F0\u97F3\uFF0C\u8981\u4E48\u5173\u6389\u7535\u89C6\uFF0C\u8981\u662F\u8FD8\u8FD9\u6837\u4EE5\u540E\u4F60\u665A\u4E0A\u80FD\u7761\u7740\u6211\u7B97\u4F60\u5389\u5BB3\u3002</p><p>\u8FD9\u79CD\u50BB\u903C\u4E1C\u897F\uFF0C\u8981\u662F\u4F60\u597D\u8BF4\u8BDD\uFF0C\u4E0D\u77E5\u9053\u5F97\u600E\u4E48\u6B3A\u8D1F\u4F60\uFF0C\u5BF9\u4ED8\u8FD9\u79CD\u4EBA\u5C31\u5F97\u4E0D\u6309\u5957\u8DEF\u51FA\u724C\u3002</p><p>\u884C\u4E86\uFF0C\u58F0\u97F3\u5173\u5C0F\u4E86\uFF0C\u8033\u6735\u6CA1\u6BDB\u75C5\u5C31\u975E\u8981\u5F00\u592A\u5927\u58F0\uFF0C\u767D\u5929\u65E0\u6240\u8C13\uFF0C\u51CC\u6668\u8FD9\u4E48\u505A\u4E0D\u662F\u6709\u75C5\u662F\u4EC0\u4E48\u3002</p><hr><p>\u5410\u69FD\u5B8C\u4E86\u3002</p><p>\u6211\u89C9\u5F97\u6211\u7B97\u662F\u7D20\u8D28\u5F88\u597D\u7684\u4E86\uFF0C\u5E73\u65F6\u4E0D\u7BA1\u5E72\u4EC0\u4E48\uFF0C\u90FD\u8981\u5148\u8003\u8651\u4F1A\u4E0D\u4F1A\u5F71\u54CD\u5230\u522B\u4EBA\u3002\u4F46\u662F\u9047\u4E0A\u8FD9\u79CD\u8138\u76AE\u539A\u7684\u4EBA\uFF0C\u4F60\u5C31\u4E0D\u80FD\u6309\u7167\u5E38\u7406\u51FA\u724C\uFF0C\u4F60\u8D8A\u662F\u597D\u8BF4\u8BDD\u5C31\u8D8A\u662F\u4F1A\u8BA9\u522B\u4EBA\u8E6C\u9F3B\u5B50\u4E0A\u8138\u3002\u4F60\u5C31\u5F97\u6BD4\u8FD9\u4E9B\u72D7\u4E1C\u897F\u66F4\u65E0\u803B\uFF0C\u66F4\u96BE\u8BF4\u8BDD\uFF0C\u8BA9\u4ED6\u4EEC\u89C9\u5F97\u4F60\u4E0D\u662F\u5584\u832C\uFF0C\u4ED6\u4EEC\u624D\u4F1A\u597D\u597D\u505A\u4EBA\u3002</p><p>\u5982\u679C\u8FD8\u6709\u4E0B\u6B21\u7684\u8BDD\uFF0C\u53EF\u80FD\u5C31\u6CA1\u8FD9\u4E48\u7B80\u5355\u4E86\uFF0C\u56E0\u4E3A\u6572\u95E8\u5DF2\u7ECF\u9EBB\u6728\u4E86\uFF0C\u6CA1\u7528\u4E86\u3002</p><p>\u5982\u679C\u8FD8\u6709\u4E0B\u6B21\uFF0C\u5C31\u8003\u8651\u76F4\u63A5\u6839\u6CBB\uFF0C\u6211\u6709\u5404\u79CD\u4ED6\u60F3\u4E0D\u5230\u7684\u529E\u6CD5\uFF0C\u4E00\u6B21\u6027\u628A\u8FD9\u79CD\u50BB\u903C\u5F81\u670D\uFF01\u8981\u662F\u6709\u4E0B\u6B21\u6211\u4F1A\u518D\u66F4\u65B0\u7684\uFF0C\u5982\u679C\u6CA1\u6709\u66F4\u65B0\u7684\u8BDD\uFF0C\u4F30\u8BA1\u5C31\u662F\u697C\u4E0A\u5DF2\u7ECF\u6539\u6389\u4E86\u81ED\u6BDB\u75C5\uFF0C\u9009\u62E9\u91CD\u65B0\u505A\u4EBA\u4E86\u3002</p>",35),_=[c];function s(a,n){return r(),e("div",null,_)}var l=p(t,[["render",s],["__file","poor-neighbors.html.vue"]]);export{l as default};
